# ─────────────────────────────────────────────────────────────────────────────
# STEP 2 – Append new products to products.csv
# ─────────────────────────────────────────────────────────────────────────────
existing_slugs = set()
with open(f"{BASE}/products.csv", "r", newline="", encoding="utf-8") as f:
    reader = csv.reader(f)
    next(reader)  # skip header
    for row in reader:
        if len(row) >= 4:
            existing_slugs.add(row[3])

new_products = [p for p in RSS_PRODUCTS if p["slug"] not in existing_slugs]
print(f"Feed entries found: {len(RSS_PRODUCTS)}  |  Already in products.csv: {len(RSS_PRODUCTS)-len(new_products)}  |  New to add: {len(new_products)}")

if new_products:
    with open(f"{BASE}/products.csv", "a", newline="", encoding="utf-8") as f:
        writer = csv.writer(f, quoting=csv.QUOTE_MINIMAL)
        for p in new_products:
            url = f"https://www.producthunt.com/posts/{p['slug']}"
            writer.writerow([
                p["id"], url, p["name"], p["slug"],
                p["desc"], p["desc"][:200],
                0, 0, NOW, p["launch"], "new",
                "", "", NOW, "", "", "", "", NOW, NOW
            ])
    print(f"✓ Appended {len(new_products)} rows to products.csv")

# ─────────────────────────────────────────────────────────────────────────────
# STEP 3 – Filter unanalyzed
# ─────────────────────────────────────────────────────────────────────────────
analyzed_ids = set()
with open(f"{BASE}/analyzed_ids.csv", "r", newline="", encoding="utf-8") as f:
    reader = csv.reader(f)
    next(reader)
    for row in reader:
        if row and row[0].strip():
            analyzed_ids.add(int(row[0].strip()))

unanalyzed = [p for p in new_products if p["id"] not in analyzed_ids]
print(f"Unanalyzed products: {len(unanalyzed)}")

# ─────────────────────────────────────────────────────────────────────────────
# STEP 4 – Quick scoring filter (op_score >= 6)
# ─────────────────────────────────────────────────────────────────────────────
passing = []
for p in unanalyzed:
    op_score, mv_score, complexity = SCORES.get(p["id"], (0, 0, "low"))
    if op_score >= 6:
        passing.append(p["id"])
print(f"Products passing quick score (op>=6): {len(passing)}")

# ─────────────────────────────────────────────────────────────────────────────
# STEP 6C – Append ALL unanalyzed IDs to analyzed_ids.csv
# ─────────────────────────────────────────────────────────────────────────────
with open(f"{BASE}/analyzed_ids.csv", "a", newline="", encoding="utf-8") as f:
    writer = csv.writer(f, quoting=csv.QUOTE_MINIMAL)
    for p in unanalyzed:
        writer.writerow([p["id"]] + [""] * 19)
print(f"✓ Marked {len(unanalyzed)} products as analyzed in analyzed_ids.csv")

# ─────────────────────────────────────────────────────────────────────────────
# STEP 6A – Append full analyses to analysis_history.csv
# ─────────────────────────────────────────────────────────────────────────────
passing_ids = set(passing)
to_write = [a for a in ANALYSES if a["product_id"] in passing_ids]

with open(f"{BASE}/analysis_history.csv", "a", newline="", encoding="utf-8") as f:
    writer = csv.writer(f, quoting=csv.QUOTE_MINIMAL)
    for a in to_write:
        writer.writerow([
            a["product_id"],
            a["product_name"],
            a["product_url"],
            a["category"],
            a["value_proposition"],
            a["target_audience"],
            a["pain_points"],
            a["improvement_opportunities"],
            a["feature_gaps"],
            a["competitors"],
            a["market_viability_score"],
            a["opportunity_score"],
            a["differentiation_strategies"],
            a["technical_complexity"],
            a["estimated_build_time"],
            a["monetization_ideas"],
            a["red_flags"],
            a["recommended_approach"],
            a["key_insights"],
            a["analyzed_at"],
        ])
print(f"✓ Appended {len(to_write)} full analyses to analysis_history.csv")
print("Done.")
